import { ComponentModule } from '@/main';
import { authenticate, getAuthenticatedUser } from '@/services/auth.service';

export default {
    name: () => 'login',
    template: () => import('./login.html?raw'),
    data: () => ({
        loading: true,
        submitting: false,
        async init() {
            console.log('login@init');

            await getAuthenticatedUser(); // Redirect home if user already logged in

            this.loading = false;
        },
        async submit(e: SubmitEvent) {
            try {
                console.log('login@submit');
                this.submitting = true;

                /** @ts-expect-error 2339 */
                await authenticate(e.target?.username?.value, e.target?.password?.value);

                this.$router.redirect('/');
            } catch (error: any) {
                console.error(error);
                this.submitting = false;
            }
        },
    }),
} as ComponentModule;
